import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatWithHeaderTest {

    @Test
    void testWithHeader_nullResultSet() throws SQLException {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeader((ResultSet) null);
        // Should call withHeader with null metaData and return a CSVFormat
        assertNotNull(result);
        // The returned format should not be the same instance (immutable pattern)
        assertNotSame(format, result);
        // The header should be null (no header)
        assertNull(result.getHeader());
    }

    @Test
    void testWithHeader_resultSetWithNullMetaData() throws SQLException {
        CSVFormat format = CSVFormat.DEFAULT;
        ResultSet resultSet = mock(ResultSet.class);
        when(resultSet.getMetaData()).thenReturn(null);
        CSVFormat result = format.withHeader(resultSet);
        assertNotNull(result);
        assertNotSame(format, result);
        assertNull(result.getHeader());
        verify(resultSet).getMetaData();
    }

    @Test
    void testWithHeader_resultSetWithMetaData() throws SQLException {
        CSVFormat format = CSVFormat.DEFAULT;
        ResultSet resultSet = mock(ResultSet.class);
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);

        when(resultSet.getMetaData()).thenReturn(metaData);
        when(metaData.getColumnCount()).thenReturn(3);
        when(metaData.getColumnLabel(1)).thenReturn("col1");
        when(metaData.getColumnLabel(2)).thenReturn("col2");
        when(metaData.getColumnLabel(3)).thenReturn("col3");

        CSVFormat result = format.withHeader(resultSet);

        assertNotNull(result);
        assertNotSame(format, result);
        String[] header = result.getHeader();
        assertNotNull(header);
        assertArrayEquals(new String[]{"col1", "col2", "col3"}, header);

        verify(resultSet).getMetaData();
        verify(metaData).getColumnCount();
        verify(metaData, times(3)).getColumnLabel(anyInt());
    }

    @Test
    void testWithHeader_resultSetThrowsSQLException() throws SQLException {
        CSVFormat format = CSVFormat.DEFAULT;
        ResultSet resultSet = mock(ResultSet.class);
        when(resultSet.getMetaData()).thenThrow(new SQLException("meta data error"));

        SQLException thrown = assertThrows(SQLException.class, () -> format.withHeader(resultSet));
        assertEquals("meta data error", thrown.getMessage());
        verify(resultSet).getMetaData();
    }
}
